412   void copysign(const KnownFPClass &Sign) {
413     // Don't know anything about the sign of the source. Expand the possible set
414     // to its opposite sign pair.
415     if (KnownFPClasses & fcZero)
416       KnownFPClasses |= fcZero;
417     if (KnownFPClasses & fcSubnormal)
418       KnownFPClasses |= fcSubnormal;
419     if (KnownFPClasses & fcNormal)
420       KnownFPClasses |= fcNormal;
421     if (KnownFPClasses & fcInf)
422       KnownFPClasses |= fcInf;
423 
424     // Sign bit is exactly preserved even for nans.
